import { create } from 'zustand';

// ✅ Interface alignée sur ton nouveau Schéma Prisma
interface Message {
  id: string;
  name: string;
  whatsapp: string; // Mis à jour (anciennement email)
  subject: string;
  content: string;
  date: string;
  status: 'nouveau' | 'lu';
}

interface Project {
  id: string;
  title: string;
  client: string;
  type: string;
  description: string;
  images: string[];
  stars: number;
  date: string;
}

interface TigerStore {
  projects: Project[];
  messages: Message[];
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (password: string) => boolean;
  logout: () => void;
  fetchData: () => Promise<void>;
  addMessage: (msg: Omit<Message, 'id' | 'date' | 'status'>) => Promise<boolean>;
  addProject: (project: Omit<Project, 'id' | 'date' | 'stars'>) => Promise<boolean>;
  deleteProject: (id: string) => Promise<void>;
  addStar: (projectId: string) => Promise<void>;
}

export const useProjectStore = create<TigerStore>((set, get) => ({
  projects: [],
  messages: [],
  isAuthenticated: false,
  isLoading: false,

  // --- AUTHENTIFICATION ---
  login: (password: string) => {
    if (password === 'Tiger2026') {
      set({ isAuthenticated: true });
      return true;
    }
    return false;
  },
  logout: () => set({ isAuthenticated: false }),

  // --- SYNCHRONISATION GLOBALE (Anti-Cache) ---
  fetchData: async () => {
    set({ isLoading: true });
    try {
      const timestamp = Date.now(); // 💡 Casse le cache navigateur
      const [resProj, resMsg] = await Promise.all([
        fetch(`/api/projects?t=${timestamp}`),
        fetch(`/api/messages?t=${timestamp}`)
      ]);

      if (!resProj.ok || !resMsg.ok) throw new Error("Erreur de communication avec le serveur");

      const projects = await resProj.json();
      const messages = await resMsg.json();

      set({
        projects: Array.isArray(projects) ? projects : [],
        messages: Array.isArray(messages) ? messages : []
      });
    } catch (error) {
      console.error("❌ Erreur de synchronisation :", error);
    } finally {
      set({ isLoading: false });
    }
  },

  // --- ACTIONS ---

  addMessage: async (msg) => {
    set({ isLoading: true });
    try {
      const res = await fetch('/api/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(msg), // Envoie bien 'whatsapp' maintenant
      });
      if (res.ok) {
        await get().fetchData(); // Rafraîchissement automatique
        return true;
      }
      return false;
    } catch (error) {
      console.error("Erreur envoi message:", error);
      return false;
    } finally {
      set({ isLoading: false });
    }
  },

  addProject: async (project) => {
    set({ isLoading: true });
    try {
      const res = await fetch('/api/projects', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(project),
      });
      if (res.ok) {
        await get().fetchData(); // Rafraîchissement automatique
        return true;
      }
      return false;
    } catch (error) {
      console.error("Erreur ajout projet:", error);
      return false;
    } finally {
      set({ isLoading: false });
    }
  },

  deleteProject: async (id) => {
    if (!confirm("⚠️ Confirmer la suppression définitive de cet ouvrage ?")) return;

    set({ isLoading: true });
    try {
      const res = await fetch(`/api/projects?id=${id}`, { method: 'DELETE' });
      if (res.ok) await get().fetchData();
    } catch (error) {
      console.error("Erreur suppression:", error);
    } finally {
      set({ isLoading: false });
    }
  },

  addStar: async (projectId) => {
    // Vote optimiste (Immédiat pour l'utilisateur)
    const currentProjects = get().projects;
    set({
      projects: currentProjects.map(p =>
        p.id === projectId ? { ...p, stars: p.stars + 1 } : p
      )
    });

    try {
      // 💡 On pointe vers /api/projects avec la méthode PATCH
      const res = await fetch(`/api/projects`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: projectId }),
      });
      // Si le serveur échoue, on recharge la vraie valeur (Rollback)
      if (!res.ok) await get().fetchData();
    } catch (error) {
      console.error("Erreur vote stars:", error);
      await get().fetchData();
    }
  },
}));